parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "subject": {
      "type": "string",
      "description": "The subject line of the email"
    },
    "body": {
      "type": "string",
      "description": "The HTML formatted body of the email"
    },
    "personalized_message": {
      "type": "string",
      "description": "The raw personalized message with variable substitution"
    }
  },
  "required": ["subject", "body", "personalized_message"]
}

